shape.script:
function getHandles(params) {
    return {
        p1: params.p1,
        p2: params.p2,
        p3: params.p3,
        p4: params.p4
    }
}

function getPath(params) {
    return [
        [params.p1.x,params.p1.y],
        [params.p2.x,params.p2.y],
        [params.p3.x,params.p3.y],
        [params.p4.x,params.p4.y],
        {closed:params.closed}
    ];
}
